<?php
namespace Ronu\LaravelFederatedAuth\DTO;
final class ExternalIdentity { public function __construct(public readonly string $provider, public readonly string $providerUserId, public readonly ?string $email=null, public readonly bool $emailVerified=false, public readonly ?string $name=null, public readonly ?string $firstName=null, public readonly ?string $lastName=null, public readonly ?string $avatarUrl=null, public readonly array $raw=[], public readonly array $claims=[], public readonly array $groups=[], public readonly array $roles=[], public readonly ?string $accessToken=null, public readonly ?string $refreshToken=null, public readonly ?int $expiresIn=null) {} public function requiresEmailButMissing(bool $requireEmail): bool { return $requireEmail && blank($this->email); } }
